var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CALL_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>여성 생존자는 구조에 성공했습니다!</color>","JPN":"<color=#ffd34c>女性生存者の救助に成功しました！</color>","ENG":"<color=#ffd34c>We've secured the female survivor!</color>","TWN":"<color=#ffd34c>成功救出女性倖存者！</color>"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CALL_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>수배자 확보! 건물 내부로 진입하겠습니다!</color>","JPN":"<color=#ffd34c>指名手配犯確保！　建物内部に進入します！</color>","ENG":"<color=#ffd34c>Felon located! We will now proceed into the building!</color>","TWN":"<color=#ffd34c>確認通緝犯！進入建築物內部！</color>"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CALL_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>뭐, 뭐야……? 이건 완전 이면세계잖아……?</color>","JPN":"<color=#ffd34c>な、何だ……？　ここは、完全に裏世界じゃないか……？</color>","ENG":"<color=#ffd34c>H-huh…? Isn't this… the Counterside?</color>","TWN":"<color=#ffd34c>這……？這根本是異界吧……？</color>"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"흐음……. 건물 청소하려면 시간 깨나 걸리겠네.","JPN":"うーん……建物の掃除にだいぶ時間がかかりそうだわ。","ENG":"Hmm... Looks like it'll take a while to clean up this mess.","TWN":"嗯……看來整理會花上一些時間。"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"하지만 뭐, 결과적으로는 서로한테 좋은 결과라고 해야 할까?","JPN":"でもまあ、最終的にはお互いに良い結果だったかしら。","ENG":"Then again, I guess this was a mutually agreeable solution?","TWN":"不過就結果而言，應該算是對雙方都好吧？"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"우리는 어쨌든 멘탈 프린팅 기술의 초안은 확보했고…….","JPN":"とりあえず私たちはメンタル・プリンティング技術の草案を確保したし……","ENG":"One way or the other, we've managed to secure an early working version of the Mental Printing technology…","TWN":"反正我們有拿到智力複印技術的初版……"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"관리국은 전세계에 <color=#ffd34c>안주할 때가 아니다</color> 라고 메시지를 보낼 수 있었잖아.","JPN":"管理局は全世界に<color=#ffd34c>安住している場合じゃない</color>とメッセージを送れたし。","ENG":"And the Administration was able to send a message to the world saying \\"<color=#ffd34c>we mustn't grow complacent yet</color>\\".","TWN":"管理局也可以對全世界發出訊息，表示<color=#ffd34c>現在不是安逸的時刻</color>。"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"1종이나 2종 같은 조무래기만 잡으면서 시시덕거리던 인간들에게는 좋은 충격요법이 되지 않았을까?","JPN":"第1種や第2種みたいな雑魚ばかり狩っていい気になっていた人間には良いショック療法になったんじゃない？","ENG":"It'll be a good shock to humans who were getting giddy about beating up small fry like Categories 1 or 2.","TWN":"這樣對那些抓到1類，或2類的小咖也在大驚小怪的人類，應該也是很棒的提醒吧？"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"안 그래, 전대장님?","JPN":"そうでしょう、戦隊長さん？","ENG":"Wouldn't you agree, Commander?","TWN":"你說是不是，戰隊長？"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"……오랜만이군, 셰나.","JPN":"……久しいな、シェナ。","ENG":"…Long time no see, Shena.","TWN":"……好久不見，世娜。"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"알렉스에게 자료를 전해 받았을 때는, 너희가 남긴 연구를 우연히 구했다고만 생각했다.","JPN":"アレックスから資料を受け取った時は、君たちが残した研究を偶然手に入れたのだと思っていたが。","ENG":"When Alex handed me the data, I thought she had stumbled on upon the research you left behind by chance.","TWN":"雅蕾克絲把資料給我時，我以為只是湊巧找到你們留下的研究。"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"알렉스? 아, 그 불량품 A 타입?","JPN":"アレックス？　ああ、あの不良品のAのこと？","ENG":"Alex? Oh, you mean the Defect Type A?","TWN":"雅蕾克絲？喔～那個A型瑕疵品喔？"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"물론 그 날 타격이 크긴 했어.","JPN":"まあ、あの日はかなりのダメージを受けたわね。","ENG":"True, we did take quite a hit that day.","TWN":"那天打擊應該很大吧。"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"조직이 무너져서 남의 집에 얹혀 사는 데다, 지휘자님은 여전히 부재 중이시니까.","JPN":"組織は崩壊して他人の家に居候している上に、指揮者様は相変わらず不在だもの。","ENG":"With our organization dismantled, we've been reduced to mooching off someone else... and the Chief Conductor's still missing.","TWN":"組織瓦解後寄人籬下，因為指揮還是不在。"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"하지만 우리는, <color=#ffd34c>엘리시움 필하모닉</color>은 죽지 않아. 여기 있는 나는 거울에 비친 상에 불과하니까.","JPN":"でもね、我々<color=#ffd34c>エリシウムフィルハーモニー</color>は死なないわ。ここにいる私は鏡に映った像に過ぎないから。","ENG":"But we of the <color=#ffd34c>Elysium Philharmonic</color> will not perish. What you see here is merely a mirror image of me.","TWN":"但我們<color=#ffd34c>愛樂組織</color>沒有瓦解，因為在這裡的我，不過是鏡子的倒影。"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"너희는…… 언제까지 그 성공할 수 없는 기술에 매달릴 셈이냐?","JPN":"君たちは……いつまでその成功の見込みもない技術にこだわるつもりだ？","ENG":"How long will you lot rely on that technology? Don't you know it'll never succeed?","TWN":"你們……到底要執著於那個不會成功的技術，到什麼時候？"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"우리한테 뭐라고 하기 전에 자기부터 되돌아보시지 그래?","JPN":"私たちに説教する前に、まず自分のことを振り返ってみたらどうかしら？","ENG":"Why don't you reflect back on yourself before you lecture us?","TWN":"在說我們之前，要不要先看看你自己？"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그 꼴로 관리국의 개 노릇을 언제까지 할 수 있을 것 같아? 쓸모가 없어지는 그 즉시 버려질걸?","JPN":"そんな格好でいつまで管理局の犬でいられると思う？　使い道がなくなった途端捨てられるわよ？","ENG":"How long do you think you can play the Administration's dog in that state? They'll discard you the moment you're no longer of use to them.","TWN":"你以為你可以當管理局的走狗多久？等你沒有利用價值後，就會被一腳踢開的！"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};